# Get the absolute directory of the current script
script_dir = Path(__file__).resolve().parent

# Go 3 levels up
target_dir = script_dir.parents[2]  # parents is zero-indexed; parents[0] is 1 level up

# Create directories
testing_dir = target_dir / "_testing" / "sm_worker"
testing_dir.mkdir(parents=True, exist_ok=True)

# Create (touch) the file
debug_file = testing_dir / "python.debug"
debug_file.touch(exist_ok=True)

# Set permissions to 777 recursively on _testing
def chmod_recursive(path, mode):
    for root, dirs, files in os.walk(path):
        os.chmod(root, mode)
        for d in dirs:
            os.chmod(os.path.join(root, d), mode)
        for f in files:
            os.chmod(os.path.join(root, f), mode)

chmod_mode = stat.S_IRWXU | stat.S_IRWXG | stat.S_IRWXO  # 0o777
chmod_recursive(target_dir / "_testing", chmod_mode)
